import React, { useMemo, useRef, useState } from "react";
import { Download, Link as LinkIcon, ListChecks, IdCard, FileSpreadsheet, UploadCloud } from "lucide-react";
import * as XLSX from "xlsx";
import "./SiparisOlustur.css";

const HEADERS = [
    "Müşteri VKN", "Müşteri Unvan", "Hizmet Tipi", "Proje Adı", "Sipariş Tarihi", "Yükleme Tarihi", "Teslim Tarihi",
    "Müşteri Sipariş No", "Müşteri Referans No", "İstenilen Araç Tipi", "Açıklama", "Yükleme Noktası", "Yükleme İli",
    "Yükleme İlçesi", "Yükleme Yeri", "Alıcı Firma", "Teslim Noktası", "Teslim İli", "Teslim İlçesi", "Teslim Yeri",
    "İrsaliye No", "İrsaliye Miktar", "Ürün", "Kap Adet", "Ambalaj Tipi", "Brüt KG", "M3", "Desi",
];

// Dışa aktarımda bulunacak ve içe aktarımda zorunlu tutulacak başlıklar
const REQUIRED_EXPORT_HEADERS = [
    "Sipariş Tarihi",
    "Müşteri Sipariş No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Noktası",
    "Alıcı Firma",
    "Teslim Noktası",
];

const emptyRow = () => HEADERS.reduce((acc, key) => ({ ...acc, [key]: "" }), {});

export default function SiparisOlustur() {
    const [projeAdi, setProjeAdi] = useState("");
    const [rows, setRows] = useState([]);                 // yalnızca Excel ile dolar
    const [dragActive, setDragActive] = useState(false);
    const [error, setError] = useState("");
    const [lastFile, setLastFile] = useState(null);
    const fileInputRef = useRef(null);

    const columns = useMemo(() => HEADERS, []);

    // --- Şablon indir / dışa aktar ---
    const handleTemplateDownload = () => {
        // Şablon sadece zorunlu/dışa aktarılacak 7 başlığı içersin
        const cols = REQUIRED_EXPORT_HEADERS;
        const wsData = [cols, ...[emptyRow()].map(r => cols.map(c => r[c] ?? ""))];
        const ws = XLSX.utils.aoa_to_sheet(wsData);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Sablon");
        XLSX.writeFile(wb, `Siparis_Sablon_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleExportExcel = () => {
        // Yalnızca REQUIRED_EXPORT_HEADERS sırasıyla dışa aktar
        const data = rows.map(r => {
            const obj = {};
            REQUIRED_EXPORT_HEADERS.forEach(h => (obj[h] = r[h] ?? ""));
            return obj;
        });
        const ws = XLSX.utils.json_to_sheet(data, { header: REQUIRED_EXPORT_HEADERS });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Siparisler");
        XLSX.writeFile(wb, `Siparisler_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    // --- Demo aksiyonlar (stub) ---
    const handleEslesmeYap = () => alert("Eşleşme işlemi tetiklendi (API bağlayın).");
    const handleEslesmeIdGetir = () => {
        const fakeId = Math.random().toString(36).slice(2, 10).toUpperCase();
        alert(`Eşleşme ID'si: ${fakeId}`);
    };

    // --- Excel içe aktarım ---
    const isExcelFile = (file) =>
        /\.(xlsx|xlsm|xls)$/i.test(file.name) ||
        [
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.ms-excel",
        ].includes(file.type);

    const normalize = (s) => String(s || "").trim();

    const parseExcel = async (file) => {
        setError("");
        try {
            if (!isExcelFile(file)) throw new Error("Lütfen .xlsx / .xls dosyası yükleyin.");
            const data = await file.arrayBuffer();
            const wb = XLSX.read(data, { type: "array" });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });
            if (!aoa || aoa.length === 0) throw new Error("Boş sayfa görünüyor.");

            const [rawHeaders, ...body] = aoa;
            const headerIndexMap = {};
            HEADERS.forEach((h) => {
                const idx = rawHeaders.findIndex((x) => normalize(x) === normalize(h));
                headerIndexMap[h] = idx; // -1 olabilir
            });

            // Zorunlu başlıklar: dışa aktarılanlarla birebir aynı
            const required = REQUIRED_EXPORT_HEADERS;
            const missing = required.filter((h) => headerIndexMap[h] === -1);
            if (missing.length) throw new Error(`Eksik başlık: ${missing.join(", ")}. Lütfen şablonu kullanın.`);

            const parsedRows = body
                .filter((row) => row.some((cell) => normalize(cell) !== ""))
                .map((row) => {
                    const obj = {};
                    HEADERS.forEach((h) => {
                        const idx = headerIndexMap[h];
                        obj[h] = idx >= 0 ? normalize(row[idx]) : "";
                    });
                    return obj;
                })
                .map((r) => ({ ...r, ["Proje Adı"]: r["Proje Adı"] || projeAdi || "" }));

            setRows(parsedRows);
            setLastFile(file);
        } catch (e) {
            setRows([]);
            setError(e.message || "Excel okunamadı.");
        }
    };

    // Drag & drop handlers (yalnızca tablo içi dropzone)
    const onDrop = (e) => {
        e.preventDefault();
        setDragActive(false);
        const f = e.dataTransfer.files?.[0];
        if (f) parseExcel(f);
    };
    const onDragOver = (e) => { e.preventDefault(); setDragActive(true); };
    const onDragLeave = () => setDragActive(false);
    const pickFile = () => fileInputRef.current?.click();
    const onFileChange = (e) => {
        const f = e.target.files?.[0];
        if (f) parseExcel(f);
        e.target.value = ""; // aynı dosya tekrar seçildiğinde tetiklensin
    };

    return (
        <div className="so-page">
            <div className="so-header">
                <div>
                    <h1 className="so-title">Sipariş Oluştur</h1>
                    <div className="so-subtitle">SiparisOlustur.js</div>
                </div>
            </div>

            {/* ÜSTTE AYRIK İKİ PANEL */}
            <div className="so-grid so-grid--two">
                {/* Sol panel: Proje seçimi */}
                <div className="so-card so-equal">
                    <label className="so-label">Proje Adı</label>
                    <select className="so-input" value={projeAdi} onChange={(e) => setProjeAdi(e.target.value)}>
                        <option value="">Seçiniz</option>
                        <option>Proje A</option>
                        <option>Proje B</option>
                        <option>Proje C</option>
                    </select>
                    <p className="so-help">Tablo elle yazılamaz. Excel içe aktarımıyla doldurulur.</p>
                </div>

                {/* Sağ panel: butonlar */}
                <div className="so-card so-equal">
                    <div className="so-actions">
                        <button className="so-btn so-btn-primary" onClick={handleTemplateDownload}>
                            <Download size={18} /> Şablonu İndir
                        </button>
                        <button className="so-btn" onClick={handleEslesmeYap}>
                            <LinkIcon size={18} /> Eşleşme Yap
                        </button>
                        <button className="so-btn" onClick={handleEslesmeIdGetir}>
                            <IdCard size={18} /> Eşleşme ID’lerini Getir
                        </button>
                        <button className="so-btn" onClick={handleExportExcel} disabled={!rows.length}>
                            <FileSpreadsheet size={18} /> Dışarı Excel Aktarma
                        </button>
                    </div>
                </div>
            </div>

            {/* ALT PANEL: BAŞLIKLAR + TABLO İÇİ DROPZONE */}
            <div className="so-table-card">
                <div className="so-table-header">
                    <ListChecks size={18} /> <span>Şablon</span>
                    <span className="so-table-sub">(İçerik yalnızca Excel ile yüklenir)</span>
                </div>

                <div className="so-table-wrap">
                    <table className="so-table">
                        <thead>
                            <tr>
                                <th className="so-index">#</th>
                                {columns.map((c) => (
                                    <th key={c}>{c}</th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {rows.length === 0 ? (
                                <tr className="so-drop-row">
                                    <td className="so-index" colSpan={columns.length + 1}>
                                        <div
                                            className={`so-drop-in-table ${dragActive ? "active" : ""}`}
                                            onDrop={onDrop}
                                            onDragOver={onDragOver}
                                            onDragLeave={onDragLeave}
                                            onDragEnd={onDragLeave}
                                            onDragExit={onDragLeave}
                                            onClick={pickFile}
                                            role="button"
                                            aria-label="Excel sürükleyip bırak veya tıklayıp seç"
                                            tabIndex={0}
                                        >
                                            <UploadCloud size={30} />
                                            <div className="so-drop-title">Excel’i buraya sürükleyip bırakın</div>
                                            <div className="so-drop-sub">ya da <b>tıklayın</b> (.xlsx / .xls)</div>
                                            <input
                                                ref={fileInputRef}
                                                type="file"
                                                accept=".xlsx,.xls,.xlsm"
                                                onChange={onFileChange}
                                                hidden
                                            />
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                rows.map((row, rowIdx) => (
                                    <tr key={rowIdx}>
                                        <td className="so-index">{rowIdx + 1}</td>
                                        {columns.map((col) => (
                                            <td key={`${rowIdx}-${col}`}>
                                                <div className="so-cell-text">{row[col]}</div>
                                            </td>
                                        ))}
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                <div className="so-footnote">
                    İpucu: “Şablonu İndir” ile başlıkları hazır Excel elde edip, doldurduktan sonra buraya yükleyebilirsiniz.
                </div>

                {error && <p className="so-error">{error}</p>}
                {lastFile && <p className="so-help">Yüklü: <b>{lastFile.name}</b></p>}
            </div>
        </div>
    );
}
